insert into content_pages (slug, surface, payload, notes, is_live)
values (
  '/', 'marketing',
  $json${"slug":"/","surface":"marketing","seo":{"title":"FounderFirst — bookkeeping that runs itself","description":"Penny is your autonomous 24/7 bookkeeper. Clean books, real profit, and chased invoices — so you can focus on your business.","keyFacts":["Penny is an autonomous 24/7 bookkeeper for small business owners.","Penny connects with read-only access and can never move your money.","Keeps books clean and CPA-ready every day of the year.","Join 100+ founders on the waitlist; first 3 months free."]},"sections":[{"type":"hero","position":0,"data":{"headline":"Bookkeeping that runs itself.","sub":"Meet Penny — your autonomous 24/7 bookkeeper. She sorts every transaction, chases late invoices, and keeps you CPA-ready. You just run the business.","ctaLabel":"Claim 3 months free","image":"/hero.png","cards":[{"label":"Stripe payout","sub":"Revenue","value":"+$4,820"},{"label":"Terra Wholesale","sub":"Cost of goods","value":"−$1,240"},{"label":"Card · Fuel","sub":"Auto-categorized","value":"−$64"}]}},{"type":"features","position":1,"data":{"headline":"Penny handles the books and the chasing — so you can focus on your business.","items":[{"icon":"chart","title":"Know your real profit","body":"Not just revenue — what you actually keep, updated as the money moves."},{"icon":"bell","title":"Never chase a payment","body":"Penny sends friendly reminders on late invoices, in your voice."},{"icon":"shield","title":"Always CPA-ready","body":"Clean, categorized books with receipts matched — every day of the year."}]}},{"type":"tryPenny","position":2,"data":{"eyebrow":"Try Penny","headline":"See Penny work — for real, right now.","ownerSub":"Connect an account and Penny starts watching. She categorizes every transaction and shows you a card. You confirm with a tap — she remembers it next time.","cpaSub":"Keep QuickBooks or Xero — nothing to migrate. Penny does the data entry your client always forgets and queues it for you. You review, approve, and export in your usual format."}},{"type":"comparison","position":3,"data":{"scatterLabel":"Today · scattered","scatter":[{"source":"Stripe","value":"$4,820"},{"source":"PayPal","value":"$1,240"},{"source":"Bank","value":"$8,100"},{"source":"Credit card","value":"−$2,340"},{"source":"Receipts","value":"12 unsorted"},{"source":"Invoices","value":"3 overdue"}],"unifiedLabel":"With Penny · one view","profitLabel":"Real profit · this month","profitValue":"$8,420","profitMeta":"Revenue $14,200 · Costs $5,780","rows":[{"label":"Books","value":"✓ clean"},{"label":"CPA readiness","value":"✓ on track"},{"label":"Late invoices","value":"↪ nudging"}]}},{"type":"steps","position":4,"data":{"headline":"Want Penny watching your books?","sub":"Drop your email — we'll save your spot and cover your first 3 months of bookkeeping.","steps":[{"num":"01","title":"Drop your email","body":"Takes 10 seconds. That's the whole sign-up."},{"num":"02","title":"3 months on us","body":"Your first 3 months are free when your spot opens — no card needed."},{"num":"03","title":"Refer & stack months","body":"Each founder you refer adds a free month — up to 12 total."}]}},{"type":"cta","position":5,"data":{"headline":"Want to try Penny?","sub":"Drop your email and we'll save your spot.","ctaLabel":"Claim 3 months free","note":"No spam. No pressure. Unsubscribe anytime."}},{"type":"faq","position":6,"data":{"headline":"Questions founders ask","entries":[{"question":"Can Penny move my money?","answer":"No. Penny connects with read-only access — she can see and categorize transactions, but can never move a cent or touch your accounts."},{"question":"Do I have to switch accounting software?","answer":"No. Penny keeps your books clean and CPA-ready and exports in your usual format."},{"question":"Is my financial data secure?","answer":"Yes. Bank connections run through the same encrypted infrastructure your bank uses; data is encrypted in transit and at rest."}]}}]}$json$::jsonb,
  'Fix: hero image + Try Penny + comparison (match canonical home.ts)',
